diffs.replacement:
{
  "name": "FUME BBQ Festival Onboarding",
  "description": "A gamified onboarding application for BBQ pitmasters participating in the FUME festival, designed to streamline menu, equipment, and travel logistics.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface MenuEntry {
  id: string;
  dishName: string;
  description: string;
  meatType: string;
  meatSpec: string;
  meatQty: string;
  meatDate: string;
  otherIngredients: string;
  otherQty: string;
  otherDate: string;
}

export interface EquipmentEntry {
  id: string;
  item: string;
  spec: string;
  qty: number;
  photoUrl?: string;
  dateNeeded: string;
}

export interface FuelEntry {
  id: string;
  type: string;
  spec: string;
  qty: string;
  dateNeeded: string;
}

export interface ProcessEntry {
  id: string;
  date: string;
  process: string;
  result: string;
  requirements: string[];
}

export interface StaffMember {
  id: string;
  fullName: string;
  passportNumber: string;
  passportPhoto?: string;
  dob: string;
  address: string;
  needsSupplementary: boolean;
}

export interface FlightInfo {
  numFlights: number;
  outboundAirport: string;
  outboundDate: string;
  inboundAirport: string;
  inboundDate: string;
}

export interface OnboardingData {
  teamName: string;
  menu: MenuEntry[];
  equipment: EquipmentEntry[];
  fuel: FuelEntry[];
  process: ProcessEntry[];
  staff: StaffMember[];
  flights: FlightInfo;
}

export type Step = 'intro' | 'menu' | 'equipment' | 'fuel' | 'process' | 'staff' | 'flights' | 'review';

import React from 'react';

interface Option {
  label: string;
  icon?: string;
}

interface VisualSelectorProps {
  options: Option[];
  selected: string;
  onSelect: (value: string) => void;
  label?: string;
}

export const VisualSelector: React.FC<VisualSelectorProps> = ({ options, selected, onSelect, label }) => {
  return (
    <div className="space-y-3">
      {label && <label className="text-xs uppercase tracking-widest text-gray-400 font-bold">{label}</label>}
      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-3">
        {options.map((opt) => (
          <button
            key={opt.label}
            onClick={() => onSelect(opt.label)}
            className={`flex flex-col items-center justify-center p-4 rounded-xl transition-all duration-200 border-2 ${
              selected === opt.label
                ? 'bg-orange-600 border-orange-400 scale-105 shadow-lg shadow-orange-900/20'
                : 'bg-zinc-900 border-zinc-800 hover:border-zinc-700'
            }`}
          >
            <span className="text-2xl mb-2">{opt.icon}</span>
            <span className="text-xs font-bold uppercase">{opt.label}</span>
          </button>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  Plus, 
  Trash2, 
  ArrowRight, 
  ArrowLeft, 
  CheckCircle2, 
  Flame, 
  Utensils, 
  Wrench, 
  Users, 
  Plane, 
  ClipboardList,
  Save,
  Loader2
} from 'lucide-react';
import { OnboardingData, Step, MenuEntry, EquipmentEntry, FuelEntry, StaffMember, ProcessEntry } from './types';
import { FUMELogo, MEAT_OPTIONS, FUEL_OPTIONS, EQUIPMENT_TEMPLATES, REQUIREMENT_TAGS } from './constants';
import { VisualSelector } from './components/VisualSelector';

// Note: In a real app, you would use a unique ID generator
const generateId = () => Math.random().toString(36).substr(2, 9);

const INITIAL_DATA: OnboardingData = {
  teamName: '',
  menu: [],
  equipment: [],
  fuel: [],
  process: [],
  staff: [],
  flights: {
    numFlights: 1,
    outboundAirport: '',
    outboundDate: '',
    inboundAirport: '',
    inboundDate: '',
  },
};

const STEPS: { id: Step; label: string; icon: any }[] = [
  { id: 'intro', label: 'Welcome', icon: ClipboardList },
  { id: 'menu', label: 'Menu', icon: Utensils },
  { id: 'equipment', label: 'Gear', icon: Wrench },
  { id: 'fuel', label: 'Fuel', icon: Flame },
  { id: 'process', label: 'Cook', icon: Flame },
  { id: 'staff', label: 'Team', icon: Users },
  { id: 'flights', label: 'Travel', icon: Plane },
  { id: 'review', label: 'Review', icon: CheckCircle2 },
];

export default function App() {
  const [currentStep, setCurrentStep] = useState<Step>('intro');
  const [data, setData] = useState<OnboardingData>(INITIAL_DATA);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem('fume_onboarding_data');
    if (saved) {
      try {
        setData(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse saved data");
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('fume_onboarding_data', JSON.stringify(data));
  }, [data]);

  const goToNext = () => {
    const currentIndex = STEPS.findIndex(s => s.id === currentStep);
    if (currentIndex < STEPS.length - 1) {
      setCurrentStep(STEPS[currentIndex + 1].id);
      window.scrollTo(0, 0);
    }
  };

  const goToPrev = () => {
    const currentIndex = STEPS.findIndex(s => s.id === currentStep);
    if (currentIndex > 0) {
      setCurrentStep(STEPS[currentIndex - 1].id);
      window.scrollTo(0, 0);
    }
  };

  const updateFlights = (field: keyof typeof data.flights, value: any) => {
    setData(prev => ({
      ...prev,
      flights: { ...prev.flights, [field]: value }
    }));
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      // In a real scenario, this would be a POST to your Google Apps Script Web App URL
      // const response = await fetch('YOUR_SCRIPT_URL', {
      //   method: 'POST',
      //   body: JSON.stringify(data),
      // });

      // Simulating network delay
      await new Promise(r => setTimeout(r, 2000));
      setSubmitted(true);
      localStorage.removeItem('fume_onboarding_data');
    } catch (err) {
      alert("Submission failed. Check console.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const renderProgress = () => {
    const activeIndex = STEPS.findIndex(s => s.id === currentStep);
    return (
      <div className="flex items-center justify-between mb-8 px-2 overflow-x-auto pb-4">
        {STEPS.map((step, idx) => {
          const Icon = step.icon;
          const isActive = step.id === currentStep;
          const isPast = idx < activeIndex;
          return (
            <div key={step.id} className="flex flex-col items-center min-w-[70px]">
              <div className={`w-10 h-10 rounded-full flex items-center justify-center transition-colors ${
                isActive ? 'bg-orange-600 text-white border-2 border-orange-400' : 
                isPast ? 'bg-zinc-800 text-orange-500' : 'bg-zinc-900 text-zinc-600'
              }`}>
                <Icon size={18} />
              </div>
              <span className={`text-[10px] mt-2 font-bold uppercase tracking-tighter ${isActive ? 'text-white' : 'text-zinc-600'}`}>
                {step.label}
              </span>
            </div>
          );
        })}
      </div>
    );
  };

  const renderIntro = () => (
    <div className="text-center space-y-8 animate-in fade-in duration-500">
      <FUMELogo />
      <div className="space-y-4 max-w-md mx-auto">
        <h2 className="text-3xl font-black italic uppercase tracking-tight">Pitmaster Onboarding</h2>
        <p className="text-zinc-400">Welcome to FUME BBQ Festival. We are stoked to have the best pitmasters from across the pond join us in the UK. Let's get your logistics sorted so you can focus on the smoke.</p>

        <div className="pt-6 space-y-4">
          <label className="block text-left text-xs font-bold uppercase text-zinc-500 tracking-widest">Team / Restaurant Name</label>
          <input 
            className="w-full bg-zinc-900 border-2 border-zinc-800 rounded-xl p-4 text-xl focus:border-orange-600 outline-none transition-all"
            placeholder="e.g. Texas Smokehouse"
            value={data.teamName}
            onChange={e => setData({...data, teamName: e.target.value})}
          />
        </div>
      </div>
      <button 
        disabled={!data.teamName}
        onClick={goToNext}
        className="bg-orange-600 hover:bg-orange-500 disabled:opacity-50 text-white font-black uppercase italic px-10 py-5 rounded-2xl flex items-center gap-3 mx-auto transition-transform active:scale-95"
      >
        LFG <ArrowRight size={24} />
      </button>
    </div>
  );

  const renderMenu = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-300">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-4xl font-black italic uppercase">The Menu</h2>
          <p className="text-zinc-400 mt-1">What are you firing up?</p>
        </div>
        <button 
          onClick={() => {
            const newItem: MenuEntry = {
              id: generateId(),
              dishName: '',
              description: '',
              meatType: 'Brisket',
              meatSpec: '',
              meatQty: '',
              meatDate: '',
              otherIngredients: '',
              otherQty: '',
              otherDate: '',
            };
            setData({ ...data, menu: [...data.menu, newItem] });
          }}
          className="bg-zinc-800 hover:bg-zinc-700 text-white p-4 rounded-xl flex items-center gap-2"
        >
          <Plus size={20} /> <span className="font-bold uppercase text-xs">Add Dish</span>
        </button>
      </div>

      {data.menu.length === 0 && (
        <div className="p-12 border-2 border-dashed border-zinc-800 rounded-3xl text-center text-zinc-600">
          No dishes added yet. Click "Add Dish" to start.
        </div>
      )}

      <div className="space-y-6">
        {data.menu.map((item, index) => (
          <div key={item.id} className="fume-card p-6 rounded-3xl space-y-6 relative overflow-hidden group">
            <div className="absolute top-0 left-0 w-1 h-full bg-orange-600"></div>
            <div className="flex justify-between items-start">
              <span className="text-zinc-700 font-black text-6xl absolute -top-4 -right-2 opacity-20 pointer-events-none">{index + 1}</span>
              <div className="flex-1 mr-4 space-y-4">
                <input 
                  className="w-full bg-transparent border-b-2 border-zinc-800 focus:border-orange-600 outline-none text-2xl font-bold p-2"
                  placeholder="Dish Name"
                  value={item.dishName}
                  onChange={e => {
                    const newMenu = [...data.menu];
                    newMenu[index].dishName = e.target.value;
                    setData({...data, menu: newMenu});
                  }}
                />
                <textarea 
                  className="w-full bg-zinc-900/50 rounded-xl p-3 text-zinc-300 border border-zinc-800 outline-none h-20"
                  placeholder="Short description / Serving style"
                  value={item.description}
                  onChange={e => {
                    const newMenu = [...data.menu];
                    newMenu[index].description = e.target.value;
                    setData({...data, menu: newMenu});
                  }}
                />
              </div>
              <button 
                onClick={() => {
                  setData({...data, menu: data.menu.filter(m => m.id !== item.id)});
                }}
                className="text-zinc-600 hover:text-red-500 p-2"
              >
                <Trash2 size={24} />
              </button>
            </div>

            <VisualSelector 
              label="Primary Protein"
              options={MEAT_OPTIONS} 
              selected={item.meatType} 
              onSelect={val => {
                const newMenu = [...data.menu];
                newMenu[index].meatType = val;
                setData({...data, menu: newMenu});
              }}
            />

            <div className="grid md:grid-cols-2 gap-4">
              <div className="space-y-4 bg-zinc-950/50 p-4 rounded-2xl">
                <h4 className="text-xs font-black uppercase text-orange-500 flex items-center gap-2">
                   Meat Requirements
                </h4>
                <input 
                  className="w-full bg-zinc-900 border border-zinc-800 rounded-lg p-3 text-sm"
                  placeholder="Meat Spec (e.g. Prime Grade, Whole Packer)"
                  value={item.meatSpec}
                  onChange={e => {
                    const newMenu = [...data.menu];
                    newMenu[index].meatSpec = e.target.value;
                    setData({...data, menu: newMenu});
                  }}
                />
                <div className="flex gap-2">
                  <input 
                    className="flex-1 bg-zinc-900 border border-zinc-800 rounded-lg p-3 text-sm"
                    placeholder="Qty (lbs/kg)"
                    value={item.meatQty}
                    onChange={e => {
                      const newMenu = [...data.menu];
                      newMenu[index].meatQty = e.target.value;
                      setData({...data, menu: newMenu});
                    }}
                  />
                  <input 
                    type="date"
                    className="flex-1 bg-zinc-900 border border-zinc-800 rounded-lg p-3 text-sm text-zinc-400"
                    value={item.meatDate}
                    onChange={e => {
                      const newMenu = [...data.menu];
                      newMenu[index].meatDate = e.target.value;
                      setData({...data, menu: newMenu});
                    }}
                  />
                </div>
              </div>

              <div className="space-y-4 bg-zinc-950/50 p-4 rounded-2xl">
                <h4 className="text-xs font-black uppercase text-zinc-400 flex items-center gap-2">
                  Sides & Other Ingredients
                </h4>
                <input 
                  className="w-full bg-zinc-900 border border-zinc-800 rounded-lg p-3 text-sm"
                  placeholder="Other specs (e.g. Specific sauce, rub, wood)"
                  value={item.otherIngredients}
                  onChange={e => {
                    const newMenu = [...data.menu];
                    newMenu[index].otherIngredients = e.target.value;
                    setData({...data, menu: newMenu});
                  }}
                />
                <div className="flex gap-2">
                  <input 
                    className="flex-1 bg-zinc-900 border border-zinc-800 rounded-lg p-3 text-sm"
                    placeholder="Qty"
                    value={item.otherQty}
                    onChange={e => {
                      const newMenu = [...data.menu];
                      newMenu[index].otherQty = e.target.value;
                      setData({...data, menu: newMenu});
                    }}
                  />
                  <input 
                    type="date"
                    className="flex-1 bg-zinc-900 border border-zinc-800 rounded-lg p-3 text-sm text-zinc-400"
                    value={item.otherDate}
                    onChange={e => {
                      const newMenu = [...data.menu];
                      newMenu[index].otherDate = e.target.value;
                      setData({...data, menu: newMenu});
                    }}
                  />
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderEquipment = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-300">
      <div>
        <h2 className="text-4xl font-black italic uppercase">Tools of the Trade</h2>
        <p className="text-zinc-400 mt-1">What gear do you need us to provide?</p>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
        {EQUIPMENT_TEMPLATES.map(temp => (
          <button 
            key={temp.label}
            onClick={() => {
              const newItem: EquipmentEntry = {
                id: generateId(),
                item: temp.label,
                spec: '',
                qty: 1,
                dateNeeded: '',
              };
              setData({ ...data, equipment: [...data.equipment, newItem] });
            }}
            className="p-4 bg-zinc-900 border-2 border-zinc-800 rounded-2xl hover:border-orange-600 transition-colors flex flex-col items-center"
          >
            <span className="text-3xl mb-1">{temp.icon}</span>
            <span className="text-[10px] font-black uppercase text-center">{temp.label}</span>
          </button>
        ))}
        <button 
          onClick={() => {
             const newItem: EquipmentEntry = {
                id: generateId(),
                item: 'Custom Item',
                spec: '',
                qty: 1,
                dateNeeded: '',
              };
              setData({ ...data, equipment: [...data.equipment, newItem] });
          }}
          className="p-4 bg-orange-600/10 border-2 border-orange-600/20 border-dashed rounded-2xl hover:border-orange-600 transition-colors flex flex-col items-center justify-center"
        >
          <Plus size={20} className="text-orange-500 mb-1" />
          <span className="text-[10px] font-black uppercase text-orange-500">Custom</span>
        </button>
      </div>

      <div className="grid gap-4">
        {data.equipment.map((item, index) => (
          <div key={item.id} className="fume-card p-4 rounded-2xl flex flex-wrap md:flex-nowrap items-center gap-4">
            <div className="bg-zinc-800 w-12 h-12 rounded-xl flex items-center justify-center text-xl shrink-0">
               {EQUIPMENT_TEMPLATES.find(t => t.label === item.item)?.icon || '🛠️'}
            </div>
            <div className="flex-1 min-w-[200px] space-y-1">
              <input 
                className="w-full bg-transparent font-bold outline-none"
                placeholder="Item Name"
                value={item.item}
                onChange={e => {
                  const copy = [...data.equipment];
                  copy[index].item = e.target.value;
                  setData({...data, equipment: copy});
                }}
              />
              <input 
                className="w-full bg-transparent text-xs text-zinc-500 outline-none"
                placeholder="Item specification (e.g. 500gal, 3-tier rack)"
                value={item.spec}
                onChange={e => {
                  const copy = [...data.equipment];
                  copy[index].spec = e.target.value;
                  setData({...data, equipment: copy});
                }}
              />
            </div>
            <div className="flex items-center gap-3 bg-zinc-900 rounded-lg p-1 border border-zinc-800">
               <button onClick={() => {
                 const copy = [...data.equipment];
                 copy[index].qty = Math.max(1, copy[index].qty - 1);
                 setData({...data, equipment: copy});
               }} className="w-8 h-8 flex items-center justify-center hover:bg-zinc-800 rounded">-</button>
               <span className="w-6 text-center font-bold">{item.qty}</span>
               <button onClick={() => {
                 const copy = [...data.equipment];
                 copy[index].qty += 1;
                 setData({...data, equipment: copy});
               }} className="w-8 h-8 flex items-center justify-center hover:bg-zinc-800 rounded">+</button>
            </div>
            <input 
              type="date"
              className="bg-zinc-900 border border-zinc-800 rounded-lg p-2 text-xs text-zinc-400"
              value={item.dateNeeded}
              onChange={e => {
                 const copy = [...data.equipment];
                 copy[index].dateNeeded = e.target.value;
                 setData({...data, equipment: copy});
              }}
            />
            <button 
              onClick={() => {
                setData({...data, equipment: data.equipment.filter(e => e.id !== item.id)});
              }}
              className="text-zinc-600 hover:text-red-500 p-2"
            >
              <Trash2 size={20} />
            </button>
          </div>
        ))}
      </div>
    </div>
  );

  const renderFuel = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-300">
      <div>
        <h2 className="text-4xl font-black italic uppercase">Fire & Fuel</h2>
        <p className="text-zinc-400 mt-1">What's the smoke profile?</p>
      </div>

      {data.fuel.length === 0 && (
        <div className="text-center p-12 border-2 border-dashed border-zinc-800 rounded-3xl">
           <button 
            onClick={() => {
              const newItem: FuelEntry = { id: generateId(), type: 'Post Oak', spec: '', qty: '', dateNeeded: '' };
              setData({ ...data, fuel: [...data.fuel, newItem] });
            }}
            className="bg-orange-600 hover:bg-orange-500 text-white font-bold py-3 px-6 rounded-xl"
           >
             Add Fuel Requirement
           </button>
        </div>
      )}

      {data.fuel.map((item, index) => (
        <div key={item.id} className="fume-card p-6 rounded-3xl space-y-6">
          <div className="flex justify-between">
            <h4 className="font-black uppercase text-orange-500">Fuel Line {index + 1}</h4>
            <button 
              onClick={() => setData({...data, fuel: data.fuel.filter(f => f.id !== item.id)})}
              className="text-zinc-600 hover:text-red-500"
            >
              <Trash2 size={20} />
            </button>
          </div>

          <VisualSelector 
            options={FUEL_OPTIONS}
            selected={item.type}
            onSelect={val => {
              const copy = [...data.fuel];
              copy[index].type = val;
              setData({...data, fuel: copy});
            }}
          />

          <div className="grid md:grid-cols-3 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-zinc-500 uppercase">Specification</label>
              <input 
                className="w-full bg-zinc-900 border border-zinc-800 rounded-lg p-3"
                placeholder="e.g. Seasoned Logs, 12-inch"
                value={item.spec}
                onChange={e => {
                  const copy = [...data.fuel];
                  copy[index].spec = e.target.value;
                  setData({...data, fuel: copy});
                }}
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-zinc-500 uppercase">Quantity</label>
              <input 
                className="w-full bg-zinc-900 border border-zinc-800 rounded-lg p-3"
                placeholder="e.g. 2 cords, 10 bags"
                value={item.qty}
                onChange={e => {
                  const copy = [...data.fuel];
                  copy[index].qty = e.target.value;
                  setData({...data, fuel: copy});
                }}
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-zinc-500 uppercase">Date Needed</label>
              <input 
                type="date"
                className="w-full bg-zinc-900 border border-zinc-800 rounded-lg p-3"
                value={item.dateNeeded}
                onChange={e => {
                  const copy = [...data.fuel];
                  copy[index].dateNeeded = e.target.value;
                  setData({...data, fuel: copy});
                }}
              />
            </div>
          </div>
        </div>
      ))}
      {data.fuel.length > 0 && (
        <button 
          onClick={() => {
            const newItem: FuelEntry = { id: generateId(), type: 'Post Oak', spec: '', qty: '', dateNeeded: '' };
            setData({ ...data, fuel: [...data.fuel, newItem] });
          }}
          className="w-full py-4 border-2 border-dashed border-zinc-800 rounded-2xl text-zinc-500 hover:text-orange-500 hover:border-orange-500 transition-colors uppercase font-bold text-xs"
        >
          Add Another Fuel Type
        </button>
      )}
    </div>
  );

  const renderProcess = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-300">
      <div>
        <h2 className="text-4xl font-black italic uppercase">Cook Timeline</h2>
        <p className="text-zinc-400 mt-1">What's the rhythm of your cook?</p>
      </div>

      <div className="space-y-6">
        {data.process.map((item, index) => (
          <div key={item.id} className="fume-card p-6 rounded-3xl space-y-6 relative">
             <div className="flex gap-4">
               <div className="shrink-0 flex flex-col items-center">
                  <div className="w-8 h-8 rounded-full bg-orange-600 flex items-center justify-center font-bold text-sm">
                    {index + 1}
                  </div>
                  <div className="flex-1 w-0.5 bg-zinc-800 my-2"></div>
               </div>
               <div className="flex-1 space-y-4">
                  <div className="flex justify-between items-center">
                    <input 
                      type="date"
                      className="bg-zinc-900 border border-zinc-800 rounded-lg p-2 text-sm text-zinc-400 outline-none"
                      value={item.date}
                      onChange={e => {
                        const copy = [...data.process];
                        copy[index].date = e.target.value;
                        setData({...data, process: copy});
                      }}
                    />
