  useEffect(() => {
    localStorage.setItem('fume_onboarding_data', JSON.stringify(data));
  }, [data]);

  const goToNext = () => {
    const currentIndex = STEPS.findIndex(s => s.id === currentStep);
    if (currentIndex < STEPS.length - 1) {
      setCurrentStep(STEPS[currentIndex + 1].id);
      window.scrollTo(0, 0);
    }
