  const handlePassportUpload = (index: number, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const copy = [...data.staff];
        copy[index].passportPhoto = reader.result as string;
        setData({ ...data, staff: copy });
      };
      reader.readAsDataURL(file);
    }
  };

  const updateFlights = (field: keyof typeof data.flights, value: any) => {
    setData(prev => ({
      ...prev,
      flights: { ...prev.flights, [field]: value }
    }));
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      await new Promise(r => setTimeout(r, 2000));
      setSubmitted(true);
      localStorage.removeItem('fume_onboarding_data');
    } catch (err) {
      alert("Submission failed.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const renderProgress = () => {
