           <h3 className="text-xl font-black uppercase italic mb-4">Team: {data.teamName}</h3>
           <div className="grid md:grid-cols-2 gap-4 text-sm">
             <div className="p-3 bg-zinc-900 rounded-xl">
               <span className="text-zinc-500 uppercase text-[10px] block mb-1">Supp. Staff</span>
               <span className="font-bold">{data.needsSupplementaryStaff ? `${data.supplementaryStaffQty} Requested` : 'None'}</span>
             </div>
             <div className="p-3 bg-zinc-900 rounded-xl">
               <span className="text-zinc-500 uppercase text-[10px] block mb-1">Crew Count</span>
               <span className="font-bold">{data.staff.length} Members</span>
             </div>
           </div>
        </div>

        <div className="fume-card p-6 rounded-3xl">
           <h4 className="text-orange-500 font-black uppercase text-xs mb-4">Menu Breakdown</h4>
           <div className="space-y-4">
             {data.menu.map(m => (
               <div key={m.id} className="border-l-2 border-zinc-800 pl-4 py-2">
                 <p className="font-bold text-lg">{m.dishName} <span className="text-zinc-500 text-sm italic">({m.meatType})</span></p>
                 <p className="text-xs text-zinc-400 mt-1 line-clamp-1">{m.description}</p>
                 <div className="grid grid-cols-2 md:grid-cols-4 gap-2 mt-2">
                    <span className="text-[10px] text-zinc-500">Spec: <span className="text-white">{m.meatSpec || 'N/A'}</span></span>
                    <span className="text-[10px] text-zinc-500">Total: <span className="text-white">{m.totalQty || 'N/A'}</span></span>
                    <span className="text-[10px] text-zinc-500">Daily: <span className="text-white">{m.portionTarget || 'N/A'}</span></span>
                    <span className="text-[10px] text-zinc-500">Date: <span className="text-white">{m.meatDate || 'N/A'}</span></span>
                 </div>
               </div>
             ))}
           </div>
        </div>

        <div className="fume-card p-6 rounded-3xl">
           <h4 className="text-orange-500 font-black uppercase text-xs mb-4">Equipment & Fuel</h4>
           <div className="grid md:grid-cols-2 gap-6">
             <div className="space-y-2">
               {data.equipment.map(e => (
                 <div key={e.id} className="text-xs flex justify-between border-b border-zinc-900 pb-1">
                   <span>{e.qty}x <span className="font-bold text-white">{e.item}</span></span>
                   <span className="text-zinc-500 italic">{e.dateNeeded}</span>
                 </div>
               ))}
             </div>
             <div className="space-y-2">
               {data.fuel.map(f => (
                 <div key={f.id} className="text-xs flex justify-between border-b border-zinc-900 pb-1">
                   <span className="font-bold text-white">{f.type}</span>
                   <span className="text-zinc-500 italic">{f.qty} from {f.dateNeeded}</span>
                 </div>
               ))}
             </div>
           </div>
        </div>

        <div className="fume-card p-6 rounded-3xl">
           <h4 className="text-orange-500 font-black uppercase text-xs mb-4">Travel Plan</h4>
           <div className="grid md:grid-cols-2 gap-4 text-xs">
              <div className="space-y-1">
                <span className="text-zinc-500 uppercase text-[9px]">Outbound</span>
                <p className="font-bold">{data.flights.outboundAirport} on {data.flights.outboundDate}</p>
              </div>
              <div className="space-y-1">
                <span className="text-zinc-500 uppercase text-[9px]">Return</span>
                <p className="font-bold">{data.flights.usArrivalAirport} on {data.flights.inboundDate}</p>
              </div>
           </div>
        </div>

        <button 
          onClick={handleSubmit}
          disabled={isSubmitting}
          className="w-full py-6 bg-orange-600 hover:bg-orange-500 text-white font-black uppercase italic text-2xl rounded-2xl flex items-center justify-center gap-3 transition-all active:scale-[0.98] shadow-2xl shadow-orange-900/40"
        >
          {isSubmitting ? <><Loader2 className="animate-spin" /> Sending...</> : <><Save size={28} /> Finalize!</>}
        </button>
      </div>
    </div>
  );

  if (submitted) {
    return (
      <div className="min-h-screen fume-gradient flex flex-col items-center justify-center p-6 text-center space-y-6">
        <div className="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center text-white mb-4 animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <FUMELogo />
        <h1 className="text-4xl font-black uppercase italic">SMOKE ON!</h1>
        <p className="text-zinc-400 max-w-md">Your details are on their way. We'll be in touch via WhatsApp soon to confirm everything. See you at Twickenham!</p>
        <button 
          onClick={() => { setSubmitted(false); setCurrentStep('intro'); setData(INITIAL_DATA); }}
          className="text-zinc-500 uppercase font-bold text-xs tracking-widest hover:text-white transition-colors"
        >
          Start New Form
        </button>
      </div>
    );
  }

  return (
    <div className="min-h-screen fume-gradient text-white pb-32">
      <header className="sticky top-0 z-50 p-6 flex justify-between items-center backdrop-blur-xl border-b border-zinc-900">
        <div className="flex items-center gap-2">
           <div className="w-10 h-10 bg-white text-black font-black flex items-center justify-center italic text-xl">F</div>
           <span className="font-black italic uppercase tracking-tighter text-sm hidden sm:block">FUME Onboarding</span>
        </div>
        <div className="text-xs font-bold text-zinc-500 uppercase tracking-widest px-3 py-1 bg-zinc-900 rounded-full">
           {data.teamName || 'New Pitmaster'}
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-6 pt-12">
        {currentStep !== 'intro' && renderProgress()}
        <div className="min-h-[60vh]">
          {currentStep === 'intro' && renderIntro()}
          {currentStep === 'info' && renderInfoPage()}
          {currentStep === 'menu' && renderMenu()}
          {currentStep === 'equipment' && renderEquipment()}
          {currentStep === 'fuel' && renderFuel()}
          {currentStep === 'process' && renderProcess()}
          {currentStep === 'staff' && renderStaff()}
          {currentStep === 'flights' && renderFlights()}
          {currentStep === 'review' && renderReview()}
        </div>
      </main>

      {currentStep !== 'intro' && (
        <div className="fixed bottom-0 left-0 right-0 p-6 backdrop-blur-md bg-black/60 border-t border-zinc-900 z-50">
          <div className="max-w-4xl mx-auto flex justify-between gap-4">
            <button onClick={goToPrev} className="px-8 py-4 bg-zinc-900 hover:bg-zinc-800 text-white font-bold rounded-2xl flex items-center gap-2 transition-all">
              <ArrowLeft size={20} /> <span className="hidden sm:inline">Back</span>
            </button>
            <button onClick={goToNext} disabled={currentStep === 'review'} className="flex-1 sm:flex-initial px-12 py-4 bg-orange-600 hover:bg-orange-500 disabled:opacity-0 disabled:pointer-events-none text-white font-black italic uppercase tracking-tight rounded-2xl flex items-center justify-center gap-2 transition-all active:scale-95 shadow-lg shadow-orange-900/40">
              Next <ArrowRight size={20} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Plus, 
  Trash2, 
  ArrowRight, 
  ArrowLeft, 
  CheckCircle2, 
  Flame, 
  Utensils, 
  Wrench, 
  Users, 
  Plane, 
  ClipboardList,
  Save,
  Loader2,
  Info,
  Camera,
  MapPin,
  Calendar,
  Contact
} from 'lucide-react';
import { OnboardingData, Step, MenuEntry, EquipmentEntry, FuelEntry, StaffMember, ProcessEntry } from './types';
import { FUMELogo, MEAT_OPTIONS, FUEL_OPTIONS, EQUIPMENT_TEMPLATES, REQUIREMENT_TAGS, STAFF_ROLES } from './constants';
import { VisualSelector } from './components/VisualSelector';

const generateId = () => Math.random().toString(36).substr(2, 9);

const INITIAL_DATA: OnboardingData = {
  teamName: '',
  needsSupplementaryStaff: false,
  supplementaryStaffQty: 1,
  menu: [],
  equipment: [],
  fuel: [],
  process: [],
  staff: [],
  flights: {
    outboundAirport: '',
    outboundDate: '',
    usArrivalAirport: '',
    inboundDate: '',
  },
};

const STEPS: { id: Step; label: string; icon: any }[] = [
  { id: 'intro', label: 'Welcome', icon: ClipboardList },
  { id: 'info', label: 'Vital Info', icon: Info },
  { id: 'menu', label: 'Menu', icon: Utensils },
  { id: 'equipment', label: 'Gear', icon: Wrench },
  { id: 'fuel', label: 'Fuel', icon: Flame },
  { id: 'process', label: 'Timeline', icon: Calendar },
  { id: 'staff', label: 'The Crew', icon: Users },
  { id: 'flights', label: 'Travel', icon: Plane },
  { id: 'review', label: 'Review', icon: CheckCircle2 },
];

export default function App() {
  const [currentStep, setCurrentStep] = useState<Step>('intro');
  const [data, setData] = useState<OnboardingData>(INITIAL_DATA);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('fume_onboarding_data');
    if (saved) {
      try {
        setData(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse saved data");
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('fume_onboarding_data', JSON.stringify(data));
  }, [data]);

  const goToNext = () => {
    const currentIndex = STEPS.findIndex(s => s.id === currentStep);
    if (currentIndex < STEPS.length - 1) {
      setCurrentStep(STEPS[currentIndex + 1].id);
      window.scrollTo(0, 0);
    }
  };

  const goToPrev = () => {
    const currentIndex = STEPS.findIndex(s => s.id === currentStep);
    if (currentIndex > 0) {
      setCurrentStep(STEPS[currentIndex - 1].id);
      window.scrollTo(0, 0);
    }
  };

  const handlePassportUpload = (index: number, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const copy = [...data.staff];
        copy[index].passportPhoto = reader.result as string;
        setData({ ...data, staff: copy });
      };
      reader.readAsDataURL(file);
    }
  };

  const updateFlights = (field: keyof typeof data.flights, value: any) => {
    setData(prev => ({
      ...prev,
      flights: { ...prev.flights, [field]: value }
    }));
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      await new Promise(r => setTimeout(r, 2000));
      setSubmitted(true);
      localStorage.removeItem('fume_onboarding_data');
    } catch (err) {
      alert("Submission failed.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const renderProgress = () => {
    const activeIndex = STEPS.findIndex(s => s.id === currentStep);
    return (
      <div className="flex items-center justify-between mb-8 px-2 overflow-x-auto pb-4 no-scrollbar">
        {STEPS.map((step, idx) => {
          const Icon = step.icon;
          const isActive = step.id === currentStep;
          const isPast = idx < activeIndex;
          return (
            <div key={step.id} className="flex flex-col items-center min-w-[70px]">
              <div className={`w-10 h-10 rounded-full flex items-center justify-center transition-colors ${
                isActive ? 'bg-orange-600 text-white border-2 border-orange-400' : 
                isPast ? 'bg-zinc-800 text-orange-500' : 'bg-zinc-900 text-zinc-600'
              }`}>
                <Icon size={18} />
              </div>
              <span className={`text-[10px] mt-2 font-bold uppercase tracking-tighter ${isActive ? 'text-white' : 'text-zinc-600'}`}>
                {step.label}
              </span>
            </div>
          );
        })}
      </div>
    );
  };

  const renderIntro = () => (
    <div className="text-center space-y-8 animate-in fade-in duration-500">
      <FUMELogo />
      <div className="space-y-4 max-w-md mx-auto">
        <h2 className="text-3xl font-black italic uppercase tracking-tight">Pitmaster Onboarding</h2>
        <p className="text-zinc-400">Welcome to FUME BBQ Festival 2026. Let's get your logistics sorted so you can focus on the smoke.</p>

        <div className="pt-6 space-y-4">
          <label className="block text-left text-xs font-bold uppercase text-zinc-500 tracking-widest">Team / Restaurant Name</label>
          <input 
            className="w-full bg-zinc-900 border-2 border-zinc-800 rounded-xl p-4 text-xl focus:border-orange-600 outline-none transition-all"
            placeholder="e.g. Texas Smokehouse"
            value={data.teamName}
            onChange={e => setData({...data, teamName: e.target.value})}
          />
        </div>
      </div>
      <button 
        disabled={!data.teamName}
        onClick={goToNext}
        className="bg-orange-600 hover:bg-orange-500 disabled:opacity-50 text-white font-black uppercase italic px-10 py-5 rounded-2xl flex items-center gap-3 mx-auto transition-transform active:scale-95 shadow-xl shadow-orange-900/20"
      >
        LFG <ArrowRight size={24} />
      </button>
    </div>
  );

  const renderInfoPage = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-300">
      <div className="text-center">
        <h2 className="text-4xl font-black italic uppercase">FUME 2026</h2>
      </div>

      <div className="fume-card p-8 rounded-3xl space-y-6">
        <div className="flex gap-4 items-start">
          <MapPin className="text-orange-500 shrink-0 mt-1" />
          <p className="text-lg">
            FUME 2026 is being held at the <span className="font-bold">Allianz Stadium, Twickenham, London</span>.
          </p>
        </div>

        <div className="flex gap-4 items-start">
          <Calendar className="text-orange-500 shrink-0 mt-1" />
          <p className="text-lg">
            The live dates are <span className="text-orange-500 font-bold underline">Thursday 11th to Sunday 14th of June</span>. 
            Site access is available from Monday 8th of June.
          </p>
        </div>

        <div className="p-6 bg-orange-600/10 rounded-2xl border-l-4 border-orange-600 space-y-3">
          <h4 className="font-black uppercase flex items-center gap-2 text-orange-400">
            <Users size={18} /> Important Traffic Info
          </h4>
          <p className="text-sm leading-relaxed text-zinc-300">
            There are <span className="text-white font-bold">5000 people coming per day</span> on Thursday, Friday, and Saturday. 
            Sunday will see about 3500 visitors. Hunger is at an all-time high! Please consider ingredients ordering, 
            speed of service, and simplicity to make your lives easier.
          </p>
        </div>

        <div className="flex gap-4 items-start pt-4 border-t border-zinc-800">
          <Contact className="text-zinc-500 shrink-0 mt-1" />
          <p className="text-xs text-zinc-400">
            If anything is unclear, please email <span className="text-white">dan@savourfestival</span> and <span className="text-white">alex@savourfestival</span>, or use the WhatsApp group.
          </p>
        </div>
      </div>
    </div>
  );

  const renderMenu = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-300">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-4xl font-black italic uppercase">The Menu</h2>
          <p className="text-zinc-400 mt-1">What's hitting the smoker?</p>
        </div>
        <button 
          onClick={() => {
            const newItem: MenuEntry = {
              id: generateId(),
              dishName: '',
              description: '',
              meatType: 'Brisket',
              meatSpec: '',
              weightPerCut: '',
              totalQty: '',
              portionTarget: '',
              meatDate: '',
              otherIngredients: [],
              otherDate: '',
            };
            setData({ ...data, menu: [...data.menu, newItem] });
          }}
          className="bg-zinc-800 hover:bg-zinc-700 text-white px-4 py-3 rounded-xl flex items-center gap-2 font-bold uppercase text-xs"
        >
          <Plus size={16} /> Add Dish
        </button>
      </div>

      <div className="space-y-8">
        {data.menu.map((item, index) => (
          <div key={item.id} className="fume-card p-6 rounded-3xl space-y-6 relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1.5 h-full bg-orange-600"></div>
            <div className="flex justify-between items-start">
              <input 
                className="w-full bg-transparent border-b-2 border-zinc-800 focus:border-orange-600 outline-none text-2xl font-bold p-2"
                placeholder="Dish Name"
                value={item.dishName}
                onChange={e => {
                  const copy = [...data.menu];
                  copy[index].dishName = e.target.value;
                  setData({...data, menu: copy});
                }}
              />
              <button 
                onClick={() => setData({...data, menu: data.menu.filter(m => m.id !== item.id)})}
                className="text-zinc-600 hover:text-red-500 p-2"
              >
                <Trash2 size={24} />
              </button>
            </div>

            <VisualSelector 
              label="Primary Protein"
              options={MEAT_OPTIONS} 
              selected={item.meatType} 
              onSelect={val => {
                const copy = [...data.menu];
                copy[index].meatType = val;
                setData({...data, menu: copy});
              }}
            />

            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-4 bg-zinc-950/50 p-6 rounded-2xl">
              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase text-zinc-500">Meat Specification</label>
                <input 
                  className="w-full bg-zinc-900 border border-zinc-800 rounded-lg p-3 text-sm"
                  placeholder="e.g. Prime Grade"
                  value={item.meatSpec}
                  onChange={e => {
                    const copy = [...data.menu];
                    copy[index].meatSpec = e.target.value;
                    setData({...data, menu: copy});
                  }}
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase text-zinc-500">Weight per cut</label>
                <input 
                  className="w-full bg-zinc-900 border border-zinc-800 rounded-lg p-3 text-sm"
                  placeholder="e.g. 14lbs"
                  value={item.weightPerCut}
                  onChange={e => {
                    const copy = [...data.menu];
                    copy[index].weightPerCut = e.target.value;
                    setData({...data, menu: copy});
                  }}
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase text-zinc-500">Total Quantity</label>
                <input 
                  className="w-full bg-zinc-900 border border-zinc-800 rounded-lg p-3 text-sm"
                  placeholder="e.g. 100 cases"
                  value={item.totalQty}
                  onChange={e => {
                    const copy = [...data.menu];
                    copy[index].totalQty = e.target.value;
                    setData({...data, menu: copy});
                  }}
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase text-zinc-500">Daily Portion Target</label>
                <input 
                  className="w-full bg-zinc-900 border border-zinc-800 rounded-lg p-3 text-sm"
                  placeholder="e.g. 800 per day"
                  value={item.portionTarget}
                  onChange={e => {
                    const copy = [...data.menu];
                    copy[index].portionTarget = e.target.value;
                    setData({...data, menu: copy});
                  }}
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase text-zinc-500">Date Needed on Site</label>
                <input 
                  type="date"
                  className="w-full bg-zinc-900 border border-zinc-800 rounded-lg p-3 text-sm"
                  value={item.meatDate}
                  onChange={e => {
                    const copy = [...data.menu];
                    copy[index].meatDate = e.target.value;
                    setData({...data, menu: copy});
                  }}
                />
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <h4 className="text-xs font-black uppercase text-zinc-400">Sides & Ingredients</h4>
                <button 
                  onClick={() => {
                    const copy = [...data.menu];
                    copy[index].otherIngredients.push({ id: generateId(), name: '', qty: '' });
                    setData({...data, menu: copy});
                  }}
                  className="text-orange-500 text-xs font-bold uppercase flex items-center gap-1"
                >
                  <Plus size={14} /> Add Item
                </button>
              </div>
              {item.otherIngredients.map((ing, iIdx) => (
                <div key={ing.id} className="flex gap-2">
                  <input 
                    className="flex-1 bg-zinc-900 border border-zinc-800 rounded-lg p-2 text-sm"
                    placeholder="Ingredient name"
                    value={ing.name}
                    onChange={e => {
                      const copy = [...data.menu];
                      copy[index].otherIngredients[iIdx].name = e.target.value;
                      setData({...data, menu: copy});
                    }}
                  />
                  <input 
                    className="w-24 bg-zinc-900 border border-zinc-800 rounded-lg p-2 text-sm"
                    placeholder="Qty"
                    value={ing.qty}
                    onChange={e => {
                      const copy = [...data.menu];
                      copy[index].otherIngredients[iIdx].qty = e.target.value;
                      setData({...data, menu: copy});
                    }}
                  />
                  <button onClick={() => {
                    const copy = [...data.menu];
                    copy[index].otherIngredients.splice(iIdx, 1);
                    setData({...data, menu: copy});
                  }} className="text-zinc-600 hover:text-red-500">
                    <Trash2 size={16} />
                  </button>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderEquipment = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-300">
      <div>
        <h2 className="text-4xl font-black italic uppercase">The Gear</h2>
        <p className="text-zinc-400 mt-1">What do you need on site?</p>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-3">
        {EQUIPMENT_TEMPLATES.map(temp => (
          <button 
            key={temp.label}
            onClick={() => {
              setData({ ...data, equipment: [...data.equipment, {
                id: generateId(), item: temp.label, spec: '', qty: 1, dateNeeded: ''
              }]});
            }}
            className="p-4 bg-zinc-900 border-2 border-zinc-800 rounded-2xl hover:border-orange-600 transition-colors flex flex-col items-center"
          >
            <span className="text-3xl mb-1">{temp.icon}</span>
            <span className="text-[10px] font-black uppercase text-center leading-tight">{temp.label}</span>
          </button>
        ))}
      </div>

      <div className="grid gap-4">
        {data.equipment.map((item, index) => (
          <div key={item.id} className="fume-card p-4 rounded-2xl flex flex-wrap md:flex-nowrap items-center gap-4">
            <div className="bg-zinc-800 w-12 h-12 rounded-xl flex items-center justify-center text-xl shrink-0">
               {EQUIPMENT_TEMPLATES.find(t => t.label === item.item)?.icon || '🛠️'}
            </div>
            <div className="flex-1 min-w-[200px] space-y-2">
              <input 
                className="w-full bg-transparent font-bold outline-none border-b border-zinc-800 focus:border-orange-600"
                placeholder="Item Name"
                value={item.item}
                onChange={e => {
                  const copy = [...data.equipment];
                  copy[index].item = e.target.value;
                  setData({...data, equipment: copy});
                }}
              />
              <div className="p-3 bg-orange-600/5 border border-orange-600/20 rounded-lg">
                <label className="block text-[9px] font-black uppercase text-orange-500 mb-1">IMPORTANT: Item Specification Needed</label>
