        {options.map((opt) => (
          <button
            key={opt.label}
            onClick={() => onSelect(opt.label)}
            className={`flex flex-col items-center justify-center p-5 rounded-2xl transition-all duration-300 border ${
              selected === opt.label
                ? 'bg-white text-black border-white scale-105 shadow-[0_0_30px_rgba(255,255,255,0.15)] z-10'
                : 'bg-zinc-900/40 border-zinc-800 text-zinc-400 hover:border-zinc-600 hover:bg-zinc-900/60'
            }`}
          >
            <span className="text-2xl mb-2 grayscale opacity-80">{opt.icon}</span>
            <span className="text-[10px] font-black uppercase tracking-tight">{opt.label}</span>
          </button>
        ))}
      </div>
    </div>
  );
};

