          {currentStep === 'equipment' && renderEquipment()}
          {currentStep === 'fuel' && renderFuel()}
          {currentStep === 'process' && renderProcess()}
          {currentStep === 'staff' && renderStaff()}
          {currentStep === 'flights' && renderFlights()}
          {currentStep === 'review' && renderReview()}
        </div>
      </main>

      {currentStep !== 'intro' && (
        <div className="fixed bottom-0 left-0 right-0 p-10 backdrop-blur-3xl bg-black/40 border-t border-zinc-900/50 z-50">
          <div className="max-w-5xl mx-auto flex justify-between gap-6">
            <button onClick={goToPrev} className="px-10 py-5 bg-zinc-950 border border-zinc-900 hover:border-zinc-700 text-white font-black uppercase italic rounded-full flex items-center gap-3 transition-all tracking-widest text-xs">
              <ArrowLeft size={18} strokeWidth={3} /> BACK
            </button>
            <button onClick={goToNext} disabled={currentStep === 'review'} className="flex-1 sm:flex-initial px-16 py-5 bg-white hover:bg-zinc-200 disabled:opacity-0 disabled:pointer-events-none text-black font-black italic uppercase tracking-widest rounded-full flex items-center justify-center gap-3 transition-all active:scale-95 shadow-[0_10px_40px_rgba(255,255,255,0.1)] text-xs">
              CONTINUE <ArrowRight size={18} strokeWidth={3} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

import React from 'react';

interface Option {
  label: string;
  icon?: string;
}

interface VisualSelectorProps {
  options: Option[];
  selected: string;
  onSelect: (value: string) => void;
  label?: string;
}

export const VisualSelector: React.FC<VisualSelectorProps> = ({ options, selected, onSelect, label }) => {
  return (
    <div className="space-y-4">
      {label && <label className="text-[10px] uppercase tracking-[0.2em] text-zinc-400 font-black">{label}</label>}
      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-3">
        {options.map((opt) => (
          <button
            key={opt.label}
            onClick={() => onSelect(opt.label)}
            className={`flex flex-col items-center justify-center p-5 rounded-2xl transition-all duration-300 border ${
              selected === opt.label
                ? 'bg-black text-white border-black scale-105 shadow-[0_10px_30px_rgba(0,0,0,0.1)] z-10'
                : 'bg-zinc-50 border-zinc-200 text-zinc-500 hover:border-zinc-400 hover:bg-zinc-100'
            }`}
          >
            <span className="text-2xl mb-2 opacity-90">{opt.icon}</span>
            <span className="text-[10px] font-black uppercase tracking-tight">{opt.label}</span>
          </button>
        ))}
      </div>
    </div>
  );
};

