                copy[index].qty = e.target.value;
                setData({...data, fuel: copy});
              }} />
            </div>
            <div className="space-y-3">
              <label className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">Initial Date</label>
              <input type="date" className="w-full bg-transparent border-b border-zinc-100 rounded-none p-2 focus:border-black outline-none text-black" value={item.dateNeeded} onChange={e => {
                const copy = [...data.fuel];
                copy[index].dateNeeded = e.target.value;
                setData({...data, fuel: copy});
              }} />
            </div>
          </div>
        </div>
      ))}
      <button 
        onClick={() => setData({...data, fuel: [...data.fuel, { id: generateId(), type: 'Wood', spec: '', qty: '', dateNeeded: '' }]})}
        className="w-full py-6 border border-zinc-200 border-dashed rounded-3xl text-zinc-400 font-black uppercase text-xs tracking-widest hover:border-black hover:text-black transition-all"
