        + Add Fuel Requirement
      </button>
    </div>
  );

  const renderProcess = () => (
    <div className="space-y-12 animate-in fade-in duration-500">
      <div className="flex justify-between items-end border-b border-zinc-100 pb-8">
        <div>
          <h2 className="text-5xl font-black italic uppercase tracking-tighter text-black">Timeline</h2>
