                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-zinc-400 tracking-widest">Process</label>
                  <input 
                    className="w-full bg-transparent border-b border-zinc-100 rounded-none p-2 text-sm text-black focus:border-black outline-none font-bold uppercase"
                    placeholder="e.g. START SMOKE"
                    value={item.process}
                    onChange={e => {
                      const copy = [...data.process];
                      copy[index].process = e.target.value;
                      setData({...data, process: copy});
                    }}
