                </div>
              </div>
              <button 
                onClick={() => setData({...data, process: data.process.filter(p => p.id !== item.id)})}
                className="text-zinc-200 hover:text-black p-2 transition-colors"
              >
                <Trash2 size={24} />
              </button>
            </div>
            <textarea 
              className="w-full bg-zinc-50 border border-zinc-100 rounded-2xl p-6 text-sm min-h-[100px] text-black focus:border-black outline-none"
              placeholder="Expected result / generic requirements..."
              value={item.result}
              onChange={e => {
                const copy = [...data.process];
                copy[index].result = e.target.value;
                setData({...data, process: copy});
              }}
            />
            <div className="flex flex-wrap gap-2">
              {REQUIREMENT_TAGS.map(tag => {
                const isSelected = item.requirements.includes(tag);
                return (
                  <button
                    key={tag}
                    onClick={() => {
                      const copy = [...data.process];
                      const reqs = [...copy[index].requirements];
                      if (isSelected) copy[index].requirements = reqs.filter(r => r !== tag);
                      else copy[index].requirements = [...reqs, tag];
                      setData({...data, process: copy});
                    }}
                    className={`px-3 py-1 rounded-full text-[9px] font-black uppercase transition-all ${
                      isSelected ? 'bg-black text-white' : 'bg-zinc-100 text-zinc-400 hover:bg-zinc-200'
                    }`}
                  >
                    {tag}
                  </button>
                );
              })}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderStaff = () => (
    <div className="space-y-12 animate-in fade-in duration-500">
      <div className="text-center">
        <h2 className="text-5xl font-black italic uppercase tracking-tighter text-black">The Crew</h2>
      </div>

      <div className="p-10 bg-zinc-50 border border-zinc-100 rounded-[2.5rem] flex flex-col md:flex-row items-center justify-between gap-8">
        <div>
          <h4 className="font-black uppercase tracking-[0.2em] text-black mb-1">Extra Hands Needed?</h4>
          <p className="text-xs text-zinc-400 tracking-wide">FUME can provide supplementary staff for site operations.</p>
        </div>
        <div className="flex items-center gap-6">
          {data.needsSupplementaryStaff && (
            <select 
              className="bg-black text-white border-none rounded-lg px-4 py-2 text-xs font-black outline-none"
              value={data.supplementaryStaffQty}
              onChange={e => setData({...data, supplementaryStaffQty: parseInt(e.target.value)})}
            >
              {[1,2,3,4,5,6].map(v => <option key={v} value={v}>{v} People</option>)}
            </select>
          )}
          <button 
            onClick={() => setData({...data, needsSupplementaryStaff: !data.needsSupplementaryStaff})}
            className={`w-16 h-8 rounded-full transition-all relative ${data.needsSupplementaryStaff ? 'bg-black' : 'bg-zinc-200'}`}
          >
            <div className={`absolute top-1 w-6 h-6 rounded-full transition-all ${data.needsSupplementaryStaff ? 'right-1 bg-white' : 'left-1 bg-zinc-400'}`}></div>
          </button>
        </div>
      </div>

      <div className="grid gap-8">
        {data.staff.map((member, idx) => (
          <div key={member.id} className="fume-card p-10 rounded-[3rem] space-y-10 relative bg-white">
            <div className="flex justify-between items-center border-b border-zinc-100 pb-6">
              <h4 className="font-black uppercase text-xs tracking-[0.3em] text-black">Personnel — 0{idx+1}</h4>
              <button onClick={() => setData({...data, staff: data.staff.filter(s => s.id !== member.id)})} className="text-zinc-200 hover:text-black transition-colors">
                <Trash2 size={22} />
              </button>
            </div>

            <VisualSelector 
              label="Role"
              options={STAFF_ROLES}
              selected={member.role}
              onSelect={val => {
                const copy = [...data.staff];
                copy[idx].role = val;
                setData({...data, staff: copy});
              }}
            />

            <div className="grid md:grid-cols-2 gap-10">
              <input className="bg-transparent border-b border-zinc-100 p-2 text-black focus:border-black outline-none uppercase font-bold text-sm" placeholder="Full Name" value={member.fullName} onChange={e => {
                const copy = [...data.staff]; copy[idx].fullName = e.target.value; setData({...data, staff: copy});
              }} />
              <input className="bg-transparent border-b border-zinc-100 p-2 text-black focus:border-black outline-none uppercase font-bold text-sm" placeholder="Passport #" value={member.passportNumber} onChange={e => {
                const copy = [...data.staff]; copy[idx].passportNumber = e.target.value; setData({...data, staff: copy});
              }} />
              <input type="date" className="bg-transparent border-b border-zinc-100 p-2 text-black focus:border-black outline-none text-sm" value={member.dob} onChange={e => {
                const copy = [...data.staff]; copy[idx].dob = e.target.value; setData({...data, staff: copy});
              }} />
              <input className="bg-transparent border-b border-zinc-100 p-2 text-black focus:border-black outline-none text-sm" placeholder="Address" value={member.address} onChange={e => {
                const copy = [...data.staff]; copy[idx].address = e.target.value; setData({...data, staff: copy});
              }} />
            </div>

            <div className="grid md:grid-cols-2 gap-10">
              <div>
                <label className="block text-[10px] font-black uppercase text-zinc-400 mb-4 tracking-widest">Passport Scan</label>
                <div className="relative group">
                  <input type="file" className="absolute inset-0 opacity-0 cursor-pointer z-10" accept="image/*" onChange={e => handlePassportUpload(idx, e)} />
                  <div className={`p-8 rounded-[2rem] border-2 border-dashed flex flex-col items-center justify-center transition-all ${member.passportPhoto ? 'border-black bg-black/5' : 'border-zinc-100 bg-zinc-50 hover:border-black'}`}>
                    {member.passportPhoto ? (
                      <div className="flex flex-col items-center gap-2 text-black">
                        <CheckCircle2 size={32} />
                        <span className="text-[10px] uppercase font-black">Uploaded</span>
                      </div>
                    ) : (
                      <div className="flex flex-col items-center text-zinc-300 group-hover:text-black">
                        <Camera size={32} strokeWidth={1} />
