                      </div>
                    )}
                  </div>
                </div>
              </div>

              <div className="flex flex-col justify-end">
                <button 
                  onClick={() => {
                    const copy = [...data.staff]; copy[idx].flightNeeded = !copy[idx].flightNeeded; setData({...data, staff: copy});
                  }}
                  className={`w-full py-8 rounded-[2rem] border-2 flex items-center justify-center gap-4 transition-all ${member.flightNeeded ? 'bg-black border-black text-white shadow-lg' : 'bg-zinc-50 border-zinc-100 text-zinc-300'}`}
                >
                  <Plane size={24} />
                  <span className="font-black uppercase text-xs tracking-widest">Flight Required</span>
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
      <button 
        onClick={() => setData({...data, staff: [...data.staff, { id: generateId(), fullName: '', role: 'Chef', flightNeeded: true, passportNumber: '', dob: '', address: '' }]})}
        className="w-full py-6 border border-zinc-100 border-dashed rounded-[2rem] text-zinc-400 font-black uppercase text-xs tracking-widest hover:border-black hover:text-black transition-all"
      >
        + Add Staff Member
      </button>
    </div>
  );

  const renderFlights = () => (
    <div className="space-y-12 animate-in fade-in duration-500">
      <div className="text-center">
        <h2 className="text-5xl font-black italic uppercase tracking-tighter text-black">Travel Hub</h2>
        <p className="text-xs text-zinc-400 mt-4 max-w-sm mx-auto italic uppercase tracking-widest">Note: All staff must depart from the same US airport for logistics.</p>
      </div>

      <div className="fume-card p-12 rounded-[3rem] grid md:grid-cols-2 gap-20 shadow-sm bg-white">
        <div className="space-y-10">
          <h4 className="text-black font-black italic uppercase border-b border-zinc-100 pb-4 flex items-center gap-3">
            <Plane size={24} className="rotate-45" /> Outbound (USA ➔ UK)
          </h4>
          <div className="space-y-6">
            <input className="w-full bg-transparent border-b border-zinc-100 p-2 text-xl font-bold focus:border-black outline-none uppercase text-black" placeholder="DEPARTURE HUB" value={data.flights.outboundAirport} onChange={e => updateFlights('outboundAirport', e.target.value)} />
            <input type="date" className="w-full bg-transparent border-b border-zinc-100 p-2 text-black focus:border-black outline-none" value={data.flights.outboundDate} onChange={e => updateFlights('outboundDate', e.target.value)} />
          </div>
        </div>

        <div className="space-y-10">
          <h4 className="text-black font-black italic uppercase border-b border-zinc-100 pb-4 flex items-center gap-3">
            <Plane size={24} className="rotate-[225deg]" /> Return (UK ➔ USA)
          </h4>
          <div className="space-y-6">
            <input className="w-full bg-transparent border-b border-zinc-100 p-2 text-xl font-bold focus:border-black outline-none uppercase text-black" placeholder="ARRIVAL HUB" value={data.flights.usArrivalAirport} onChange={e => updateFlights('usArrivalAirport', e.target.value)} />
            <input type="date" className="w-full bg-transparent border-b border-zinc-100 p-2 text-black focus:border-black outline-none" value={data.flights.inboundDate} onChange={e => updateFlights('inboundDate', e.target.value)} />
          </div>
        </div>
      </div>
    </div>
  );

  const renderReview = () => (
    <div className="space-y-12 animate-in fade-in duration-500 pb-20">
      <div className="text-center">
        <h2 className="text-6xl font-black italic uppercase tracking-tighter text-black">Final Review</h2>
      </div>

      <div className="space-y-8">
        <div className="fume-card p-10 rounded-[3rem] border-t-4 border-black shadow-lg bg-white">
           <h3 className="text-4xl font-black uppercase italic tracking-tighter text-black mb-10">{data.teamName}</h3>
           <div className="grid md:grid-cols-2 gap-10">
             <div className="p-6 bg-zinc-50 rounded-2xl">
               <span className="text-zinc-400 uppercase text-[9px] font-black tracking-widest block mb-2">Crew</span>
               <span className="text-xl font-black uppercase text-black">{data.staff.length} Members</span>
               <p className="text-[10px] text-zinc-500 mt-1">{data.needsSupplementaryStaff ? `+${data.supplementaryStaffQty} Supplementary` : 'Self-Sufficient'}</p>
             </div>
             <div className="p-6 bg-zinc-50 rounded-2xl">
               <span className="text-zinc-400 uppercase text-[9px] font-black tracking-widest block mb-2">Hub</span>
               <span className="text-xl font-black uppercase text-black">{data.flights.outboundAirport} Hub</span>
               <p className="text-[10px] text-zinc-500 mt-1">{data.flights.outboundDate} Departure</p>
             </div>
           </div>
        </div>

        <div className="fume-card p-10 rounded-[3rem] shadow-sm bg-white">
           <h4 className="text-zinc-400 font-black uppercase text-[10px] tracking-widest mb-8">Culinary Matrix</h4>
           <div className="space-y-4">
             {data.menu.map(m => (
               <div key={m.id} className="p-6 border border-zinc-100 rounded-2xl flex justify-between items-center bg-zinc-50/30">
                 <div>
                    <p className="font-black text-xl uppercase tracking-tighter text-black italic">{m.dishName || 'Untitled Item'}</p>
                    <p className="text-[9px] text-zinc-400 uppercase font-black">{m.meatType} • {m.totalQty || '0'} Qty • {m.portionTarget || '0'}/Day</p>
                 </div>
                 <ChevronRight className="text-zinc-200" />
               </div>
             ))}
           </div>
        </div>

        <div className="fume-card p-10 rounded-[3rem] shadow-sm bg-white">
           <h4 className="text-zinc-400 font-black uppercase text-[10px] tracking-widest mb-8">Equipment & Resources</h4>
           <div className="grid md:grid-cols-2 gap-12 text-black">
             <div className="space-y-3">
               <label className="text-[9px] font-black text-zinc-400 uppercase">Inventory</label>
               {data.equipment.map(e => (
                 <div key={e.id} className="text-xs flex justify-between border-b border-zinc-100 pb-2">
                   <span className="font-black uppercase italic">{e.qty}x {e.item}</span>
                   <span className="text-zinc-400">{e.dateNeeded}</span>
                 </div>
               ))}
             </div>
             <div className="space-y-3">
               <label className="text-[9px] font-black text-zinc-400 uppercase">Energy</label>
               {data.fuel.map(f => (
                 <div key={f.id} className="text-xs flex justify-between border-b border-zinc-100 pb-2">
                   <span className="font-black uppercase italic">{f.type}</span>
                   <span className="text-zinc-400">{f.qty}</span>
                 </div>
               ))}
             </div>
           </div>
        </div>

        <button 
          onClick={handleSubmit}
          disabled={isSubmitting}
          className="w-full py-8 bg-black hover:bg-zinc-800 text-white font-black uppercase italic text-3xl rounded-[2.5rem] flex items-center justify-center gap-4 transition-all active:scale-[0.98] shadow-2xl mt-12"
        >
          {isSubmitting ? <><Loader2 className="animate-spin" /> SUBMITTING</> : <><Save size={32} /> SUBMIT MANIFEST</>}
        </button>
      </div>
    </div>
  );

  if (submitted) {
    return (
      <div className="min-h-screen fume-gradient flex flex-col items-center justify-center p-10 text-center space-y-10">
        <div className="w-32 h-32 bg-black text-white rounded-full flex items-center justify-center shadow-2xl animate-bounce">
          <CheckCircle2 size={64} />
        </div>
        <div className="space-y-4">
          <FUMELogo />
          <h1 className="text-5xl font-black uppercase italic tracking-tighter text-black">MANIFEST RECEIVED</h1>
          <p className="text-zinc-500 text-sm max-w-sm mx-auto leading-relaxed uppercase tracking-widest">We are reviewing your footprint. Prepare for FUME 2026. Smoke on.</p>
        </div>
        <button 
          onClick={() => { setSubmitted(false); setCurrentStep('intro'); setData(INITIAL_DATA); }}
          className="text-zinc-400 uppercase font-black text-[10px] tracking-[0.5em] hover:text-black transition-colors"
        >
          NEW SUBMISSION
        </button>
      </div>
    );
  }

  return (
    <div className="min-h-screen fume-gradient text-black pb-40">
      <header className="sticky top-0 z-50 p-8 flex justify-between items-center backdrop-blur-3xl border-b border-zinc-100">
        <div className="flex items-center gap-4">
           <div className="w-12 h-12 bg-black text-white font-black flex items-center justify-center italic text-2xl shadow-lg">F</div>
           <span className="font-black italic uppercase tracking-tighter text-lg hidden sm:block">ONBOARDING</span>
        </div>
        <div className="text-[10px] font-black text-zinc-400 uppercase tracking-[0.3em] px-6 py-2 bg-zinc-50 border border-zinc-100 rounded-full">
           {data.teamName || 'PITMASTER'}
        </div>
      </header>

      <main className="max-w-5xl mx-auto p-8 pt-16">
        {currentStep !== 'intro' && renderProgress()}
        <div className="min-h-[60vh]">
          {currentStep === 'intro' && renderIntro()}
          {currentStep === 'info' && renderInfoPage()}
          {currentStep === 'menu' && renderMenu()}
          {currentStep === 'equipment' && renderEquipment()}
          {currentStep === 'fuel' && renderFuel()}
          {currentStep === 'process' && renderProcess()}
          {currentStep === 'staff' && renderStaff()}
          {currentStep === 'flights' && renderFlights()}
          {currentStep === 'review' && renderReview()}
        </div>
      </main>

      {currentStep !== 'intro' && (
        <div className="fixed bottom-0 left-0 right-0 p-10 backdrop-blur-3xl bg-white/60 border-t border-zinc-100 z-50">
          <div className="max-w-5xl mx-auto flex justify-between gap-6">
            <button onClick={goToPrev} className="px-10 py-5 bg-zinc-50 border border-zinc-200 hover:border-black text-black font-black uppercase italic rounded-full flex items-center gap-3 transition-all tracking-widest text-xs">
              <ArrowLeft size={18} /> BACK
            </button>
            <button onClick={goToNext} disabled={currentStep === 'review'} className="flex-1 sm:flex-initial px-16 py-5 bg-black hover:bg-zinc-800 disabled:opacity-0 disabled:pointer-events-none text-white font-black italic uppercase tracking-widest rounded-full flex items-center justify-center gap-3 transition-all active:scale-95 shadow-xl text-xs">
              CONTINUE <ArrowRight size={18} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export interface MenuEntry {
  id: string;
  dishName: string;
  description: string;
  meatType: string;
  meatSpec: string;
  weightPerCut: string;
  dailyPortionTarget: string; // Changed label in UI
  meatDate: string;
  otherIngredients: Array<{ id: string; name: string; qty: string }>;
  otherDate: string;
}

export interface KitchenInfo {
  needsKitchen: boolean;
  purpose: string;
  specificEquipment: string;
  photos: string[];
}

export interface HotelInfo {
  numRooms: string;
  roomSpec: string; // Individual vs Shared
  checkIn: string;
  checkOut: string;
  photos: string[];
}

export interface EquipmentEntry {
  id: string;
  item: string;
  spec: string;
  qty: number;
  dateNeeded: string;
}

export interface FuelEntry {
  id: string;
  type: string;
  spec: string;
  qty: string;
  dateNeeded: string;
}

export interface ProcessEntry {
  id: string;
  date: string;
  process: string;
  result: string;
  requirements: string[];
}

export interface StaffMember {
  id: string;
  fullName: string;
  role: string;
  flightNeeded: boolean;
  passportNumber: string;
  passportPhoto?: string;
  dob: string;
  address: string;
}

export interface FlightInfo {
  outboundAirport: string;
  outboundDate: string;
  usArrivalAirport: string;
  inboundDate: string;
}

export interface OnboardingData {
  teamName: string;
  needsSupplementaryStaff: boolean;
  supplementaryStaffQty: number;
  menu: MenuEntry[];
  kitchen: KitchenInfo;
  equipment: EquipmentEntry[];
  fuel: FuelEntry[];
  process: ProcessEntry[];
  staff: StaffMember[];
  flights: FlightInfo;
  hotel: HotelInfo;
}

export type Step = 'intro' | 'info' | 'menu' | 'kitchen' | 'equipment' | 'fuel' | 'process' | 'staff' | 'flights' | 'hotel' | 'review';

import React, { useState, useEffect } from 'react';
import { 
