    const files = e.target.files;
    if (files) {
      Array.from(files).forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          setData(prev => ({
            ...prev,
            [section]: {
              ...prev[section],
              photos: [...prev[section].photos, reader.result as string]
            }
          }));
        };
        reader.readAsDataURL(file);
      });
    }
  };

  const removePhoto = (section: 'kitchen' | 'hotel', index: number) => {
    setData(prev => ({
      ...prev,
      [section]: {
        ...prev[section],
        photos: prev[section].photos.filter((_, i) => i !== index)
      }
    }));
  };

  const handlePassportUpload = (index: number, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const copy = [...data.staff];
        copy[index].passportPhoto = reader.result as string;
        setData({ ...data, staff: copy });
      };
      reader.readAsDataURL(file);
    }
