payload.text:
To set up your FUME Onboarding backend, you will need to create a **Google Apps Script**. This script will act as a bridge, receiving the data from your web app and organizing it into different sheets within a single Google Spreadsheet.

### 1. The Apps Script Code
Create a new Google Sheet, go to **Extensions > Apps Script**, delete any existing code, and paste the following:

```javascript
/**
 * FUME Onboarding Backend
 * Instructions:
 * 1. Replace 'YOUR_SPREADSHEET_ID_HERE' with your actual Sheet ID.
 * 2. Click 'Deploy' > 'New Deployment'.
 * 3. Select 'Web App'.
 * 4. Execute as: 'Me'.
 * 5. Who has access: 'Anyone'.
 * 6. Copy the Web App URL and use it in your frontend fetch call.
 */

const SPREADSHEET_ID = 'YOUR_SPREADSHEET_ID_HERE';

function doPost(e) {
  const lock = LockService.getScriptLock();
  lock.tryLock(10000); // Wait for up to 10 seconds for other processes to finish

  try {
    const data = JSON.parse(e.postData.contents);
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const timestamp = new Date();
    const team = data.teamName || "Unknown Team";

    // 1. Menu Sheet
    const menuSheet = getOrCreateSheet(ss, "Menu", ["Timestamp", "Team", "Dish", "Protein", "Spec", "Weight", "Daily Target", "Date Needed", "Other Ingredients"]);
    data.menu.forEach(item => {
      const ingredients = item.otherIngredients.map(i => `${i.name} (${i.qty})`).join(", ");
      menuSheet.appendRow([timestamp, team, item.dishName, item.meatType, item.meatSpec, item.weightPerCut, item.dailyPortionTarget, item.meatDate, ingredients]);
    });

    // 2. Kitchen Sheet
    const kitchenSheet = getOrCreateSheet(ss, "Kitchen", ["Timestamp", "Team", "Needs Kitchen", "Purpose", "Specific Gear"]);
    kitchenSheet.appendRow([timestamp, team, data.kitchen.needsKitchen, data.kitchen.purpose, data.kitchen.specificEquipment]);

    // 3. Equipment Sheet
    const equipSheet = getOrCreateSheet(ss, "Equipment", ["Timestamp", "Team", "Item", "Spec", "Qty", "Date Needed"]);
    data.equipment.forEach(item => {
      equipSheet.appendRow([timestamp, team, item.item, item.spec, item.qty, item.dateNeeded]);
    });

    // 4. Fuel Sheet
    const fuelSheet = getOrCreateSheet(ss, "Fuel", ["Timestamp", "Team", "Type", "Spec", "Qty", "Initial Date"]);
    data.fuel.forEach(item => {
      fuelSheet.appendRow([timestamp, team, item.type, item.spec, item.qty, item.dateNeeded]);
    });

    // 5. Timeline Sheet
    const timelineSheet = getOrCreateSheet(ss, "Timeline", ["Timestamp", "Team", "Date/Time", "Process", "Result/Requirements"]);
    data.process.forEach(item => {
      timelineSheet.appendRow([timestamp, team, item.date, item.process, item.result]);
    });

    // 6. Crew Sheet
    const crewSheet = getOrCreateSheet(ss, "Crew", ["Timestamp", "Team", "Name", "Role", "Passport", "DOB", "Address", "Extra Staff Req?"]);
    data.staff.forEach(person => {
      crewSheet.appendRow([timestamp, team, person.fullName, person.role, person.passportNumber, person.dob, person.address, data.needsSupplementaryStaff ? `Yes (${data.supplementaryStaffQty})` : "No"]);
    });

    // 7. Travel Sheet
    const travelSheet = getOrCreateSheet(ss, "Travel", ["Timestamp", "Team", "Out Hub", "Out Date", "In Hub", "In Date"]);
    const f = data.flights;
    travelSheet.appendRow([timestamp, team, f.outboundAirport, f.outboundDate, f.usArrivalAirport, f.inboundDate]);

    // 8. Hotel Sheet
    const hotelSheet = getOrCreateSheet(ss, "Hotel", ["Timestamp", "Team", "Room Qty", "Spec", "Check-in", "Check-out"]);
    const h = data.hotel;
    hotelSheet.appendRow([timestamp, team, h.numRooms, h.roomSpec, h.checkIn, h.checkOut]);

    return ContentService.createTextOutput(JSON.stringify({ "result": "success" }))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({ "result": "error", "error": error.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}

function getOrCreateSheet(ss, name, headers) {
  let sheet = ss.getSheetByName(name);
  if (!sheet) {
    sheet = ss.insertSheet(name);
    sheet.appendRow(headers);
    sheet.getRange(1, 1, 1, headers.length).setFontWeight("bold").setBackground("#f3f3f3");
  }
  return sheet;
}
```

### 2. Where to put your Google Sheet URL
You don't actually put the whole URL; you just need the **Spreadsheet ID**.
1. Open your Google Sheet.
2. Look at the URL in your browser. It looks like this: `https://docs.google.com/spreadsheets/d/1abc123456789.../edit`
3. Copy the long string of letters and numbers between `/d/` and `/edit`.
4. In the code above, replace `'YOUR_SPREADSHEET_ID_HERE'` with that copied ID (keep the single quotes).

### 3. Required Column Headers
The script is designed to **automatically create the tabs and headers for you** if they don't exist. However, if you want to set them up manually, here is what each tab should contain:

| Sheet Name | Column Headers (Row 1) |
| :--- | :--- |
| **Menu** | Timestamp, Team, Dish, Protein, Spec, Weight, Daily Target, Date Needed, Other Ingredients |
| **Kitchen** | Timestamp, Team, Needs Kitchen, Purpose, Specific Gear |
| **Equipment** | Timestamp, Team, Item, Spec, Qty, Date Needed |
| **Fuel** | Timestamp, Team, Type, Spec, Qty, Initial Date |
| **Timeline** | Timestamp, Team, Date/Time, Process, Result/Requirements |
| **Crew** | Timestamp, Team, Name, Role, Passport, DOB, Address, Extra Staff Req? |
| **Travel** | Timestamp, Team, Out Hub, Out Date, In Hub, In Date |
| **Hotel** | Timestamp, Team, Room Qty, Spec, Check-in, Check-out |

### 4. Final Step: Frontend Sync
To make your "Submit" button actually send the data to this script, you would update the `handleSubmit` function in your `App.tsx` (or wherever you handle the fetch) to look like this:

```javascript
const handleSubmit = async () => {
  setIsSubmitting(true);
  try {
    const response = await fetch('YOUR_DEPLOYED_WEB_APP_URL', {
      method: 'POST',
      body: JSON.stringify(data),
    });
    setSubmitted(true);
    localStorage.removeItem('fume_onboarding_data');
  } catch (err) {
    alert("Submission failed. Check your connection.");
  } finally {
    setIsSubmitting(false);
  }
};
``` 

*Note: You must use the **Web App URL** provided by Google after you "Deploy" the script.*

