  needsKitchen: boolean;
  purpose: string;
  specificEquipment: string;
  photos: string[];
}

export interface HotelInfo {
  numRooms: string;
  roomSpec: string; // Individual vs Shared
  checkIn: string;
  checkOut: string;
  photos: string[];
}

export interface EquipmentEntry {
  id: string;
